import { createFileRoute } from '@tanstack/react-router';
import { useState, useEffect } from 'react';
import {
  listWorkflows,
  createWorkflow,
  updateWorkflow,
  deleteWorkflow,
  type Workflow,
} from '../api';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Plus, Edit, Trash2, Loader2, ArrowUp } from 'lucide-react';

export const workflowsRoute = createFileRoute({
  file: 'src/routes/workflows.tsx',
});

export default function Workflows() {
  const [workflows, setWorkflows] = useState<Workflow[]>([]);
  const [loading, setLoading] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingWorkflow, setEditingWorkflow] = useState<Workflow | null>(null);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');

  useEffect(() => {
    setLoading(true);
    listWorkflows()
      .then(setWorkflows)
      .finally(() => setLoading(false));
  }, []);

  const openDialog = (workflow?: Workflow) => {
    if (workflow) {
      setEditingWorkflow(workflow);
      setName(workflow.name);
      setDescription(workflow.description);
    } else {
      setEditingWorkflow(null);
      setName('');
      setDescription('');
    }
    setDialogOpen(true);
  };

  const closeDialog = () => {
    setDialogOpen(false);
  };

  const saveWorkflow = async () => {
    setLoading(true);
    try {
      if (editingWorkflow) {
        const updated = await updateWorkflow(editingWorkflow.id, {
          name,
          description,
        });
        setWorkflows((ws) =>
          ws.map((w) => (w.id === updated.id ? updated : w))
        );
      } else {
        const created = await createWorkflow({ name, description });
        setWorkflows((ws) => [...ws, created]);
      }
      closeDialog();
    }
